// Pegamos os dados da Query String
const query = items[0].json.query || {};

const nome = query.nome || "Visitante";
const email = (query.email || "exemplo@teste.com").toLowerCase();
const empresa = query.empresa || "Empresa não informada";

let prioridade = "Baixa";
let cor = "#2ecc71"; // Verde
let tempoResposta = "24 horas";
let categoria = "Lead Comum";

const dominiosPessoais = ["gmail.com", "hotmail.com", "outlook.com", "yahoo.com"];
const dominio = email.split('@')[1] || "";

if (dominio && !dominiosPessoais.includes(dominio)) {
  prioridade = "Alta";
  cor = "#e67e22"; // Laranja
  tempoResposta = "15 minutos";
  categoria = "Lead Corporativo (B2B)";
}

if (dominio === "n8n.io") {
  prioridade = "Crítica";
  cor = "#e74c3c"; // Vermelho
  tempoResposta = "Imediato";
  categoria = "Parceiro VIP";
}

return {
  nome,
  email,
  empresa,
  prioridade,
  cor,
  tempoResposta,
  categoria
};

